Code.Terraform:
```hcl
# 最小構成の VPC セットアップ：1 つのパブリックサブネット、2 つのプライベートサブネット、および NAT Gateway
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.0.0/24"
}

resource "aws_subnet" "private_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"  # プライベートサブネット 1（必須）
}

resource "aws_subnet" "private_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"  # プライベートサブネット 2（必須）
}

resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id               # 重要：プライベートサブネットのアウトバウンド通信には NAT が必要
  subnet_id     = aws_subnet.public.id         # 重要：NAT はパブリックサブネット内に配置する必要があります。
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {                                      # 重要：これにより、このサブネットはパブリックサブネットになります。
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {                                      # 重要：プライベートサブネットはインターネット接続に NAT を使用します。
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id     # 重要：WorkSpace のサブネットはプライベートルートテーブルに関連付ける必要があります。
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id  # 重要：少なくとも 2 つのプライベートサブネットを確保します。
}
```
